for (const item of $input.all()) {
  const json = item.json;
  const currentStock = Number(json['Current Stock']) || 0;
  const last7DaysSales = Number(json['Last 7 Days Sales']) || 0;
  const dailySales = last7DaysSales / 7;
  const rawDeliveryTime = json['Avg Delivery Time'] || json['Avg. Delivery Time'] || json['Avg. Delivery Time '] || "0";
  const leadTime = parseFloat(rawDeliveryTime.toString().replace(/[^0-9.]/g, '')) || 0;
  const dynamicBuffer = Math.max(2, Math.min(14, Math.round(14 * dailySales)));
  const targetStock = (leadTime + dynamicBuffer) * dailySales;
  json['Reorder Quantity'] = Math.max(0, Math.ceil(targetStock - currentStock));
  json['Debug - Clean Lead Time'] = leadTime;
  json['Debug - Daily Sales'] = Number(dailySales.toFixed(2));
  json['Debug - Target Stock'] = Number(targetStock.toFixed(2));
}
return $input.all();

// --- PHASE 1: DATA GATHERING & FILTERING ---

// 1. Grab the historical data (flowing directly into this node)
const orderHistory = $input.all(); 

// 2. Reach back to grab the fresh low-stock alerts
// IMPORTANT: Ensure "Edit Fields1" matches the exact name of your node!
const incomingOrders = $items("Format Reorder Data"); 

const COOLDOWN_DAYS = 14;
const now = new Date();
const itemsToOrder = [];

// 3. Loop through low stock items to filter out ineligible ones
for (const item of incomingOrders) {
    const productString = item.json.product_string; 

    const recentlyOrdered = orderHistory.some(historyItem => {
        // If the product strings don't match, skip to the next row
        if (historyItem.json.product_string !== productString) return false;

        // Make sure we are reading the status in lowercase just to be safe
        const currentStatus = (historyItem.json.status || "").toLowerCase();

        // SHIELD 1: The Status Check
        // If the order is currently pending or sent, do not reorder it!
        if (currentStatus === 'pending' || currentStatus === 'sent') {
            return true; // Flag as "recently ordered" to block it
        }

        // SHIELD 2: The 14-Day Date Check
        // If it is completely finished, check if it was ordered recently
        if (currentStatus === 'completed' && historyItem.json.reorder_date) {
            const orderDate = new Date(historyItem.json.reorder_date);

            // Safety check to ensure n8n can actually read the date format
            if (!isNaN(orderDate.getTime())) {
                const daysSinceOrder = (now - orderDate) / (1000 * 60 * 60 * 24);
                return daysSinceOrder <= COOLDOWN_DAYS; 
            }
        }

        // If it's not pending/sent, and it's older than 14 days, let it through!
        return false;
    });

    // If it passed both shields, push it to our final array to be ordered
    if (!recentlyOrdered) {
        itemsToOrder.push(item);
    }
}


// --- PHASE 2: VENDOR GROUPING ---

const groupedVendors = {};

// Iterate through the filtered, clean items to group them by Vendor
itemsToOrder.forEach(item => {
    const data = item.json;
    const vendorId = data["Vendor ID"];

    // Initialize vendor group
    if (!groupedVendors[vendorId]) {
        groupedVendors[vendorId] = {
            "Vendor ID": vendorId,
            "Vendor Name": data["Vendor Name"],
            "Email Address": data["Email Address"],
            "Products String": [],
            "Total Reorder Quantity": 0,
            "Structured Line Items": []
        };
    }

    // Use existing product_string if available, else build it
    const productString =
        data.product_string ||
        `${data["Product ID"]} (${data["Product Name"]})`;

    groupedVendors[vendorId]["Products String"].push(productString);

    // Aggregate reorder quantity
    groupedVendors[vendorId]["Total Reorder Quantity"] += Number(data["Reorder Quantity"] || 0);

    // Structured items
    groupedVendors[vendorId]["Structured Line Items"].push({
        "Product ID": data["Product ID"],
        "Product Name": data["Product Name"],
        "Reorder Quantity": data["Reorder Quantity"],
        "Current Stock": data["Current Stock"]
    });
});


// --- PHASE 3: FINAL OUTPUT FORMATTING ---

// Convert back to n8n output format
const result = Object.values(groupedVendors).map(vendor => {
    vendor["Products String"] = vendor["Products String"].join(", ");

    return {
        json: vendor
    };
});

// Output the clean, grouped list!
return result;

